import React, { useState } from 'react';

const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showReset, setShowReset] = useState(false);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] w-96 h-96 p-4 rounded-lg text-white">
        <h2 className="text-lg font-bold">User Auth Card</h2>
        <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} className="w-full h-8 p-2 my-2 bg-transparent border border-white text-white" placeholder="Username"/>
        <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full h-8 p-2 my-2 bg-transparent border border-white text-white" placeholder="Password"/>
        <button className="bg-[#B7D7CD] hover:bg-[#C06C88] text-black font-bold py-2 px-4 rounded" onClick={() => setShowReset(true)}>Reset Password</button>
        <button className="bg-[#B7D7CD] hover:bg-[#C06C88] text-black font-bold py-2 px-4 rounded" onClick={() => console.log('Login clicked')}>Login</button>
        {showReset && <p className="text-lg font-bold">Reset Password</p>}
      </div>
    </div>
  );
};

export default App;
